const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 30,
  rune: 30,
};

const PROCESSING_FEES: Record<number, number> = {
  0: 0,
  1: 5,
  2: 10,
  3: 20,
};

const calculateBasePremium = (items: Item[]): number => {
  return items.reduce(
    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
    0
  );
};

